import{_ as o,o as t,c as r,ag as l}from"./chunks/framework.DGzMGr_a.js";const u=JSON.parse('{"title":"首屏加载优化的具体手段","description":"","frontmatter":{"title":"首屏加载优化的具体手段","difficulty":"hard","tags":["首屏","性能优化","SSR","preload","代码分割"],"estimate":25},"headers":[],"relativePath":"domains/browser/qa/qa-18-first-screen-optimization.md","filePath":"domains/browser/qa/qa-18-first-screen-optimization.md","lastUpdated":1783504823000}'),s={name:"domains/browser/qa/qa-18-first-screen-optimization.md"};function i(n,e,d,c,a,g){return t(),r("div",null,[...e[0]||(e[0]=[l('<h1 id="问答-18-高级-首屏加载优化的具体手段" tabindex="-1">问答 18（高级）：首屏加载优化的具体手段 <a class="header-anchor" href="#问答-18-高级-首屏加载优化的具体手段" aria-label="Permalink to &quot;问答 18（高级）：首屏加载优化的具体手段&quot;">​</a></h1><h2 id="题目" tabindex="-1">题目 <a class="header-anchor" href="#题目" aria-label="Permalink to &quot;题目&quot;">​</a></h2><p>如何优化首屏加载？请从 HTML / CSS / JS / 图片 / 数据请求 / 渲染架构等多个层面给出具体手段，并说明各自的适用场景。</p><h2 id="参考答案" tabindex="-1">参考答案 <a class="header-anchor" href="#参考答案" aria-label="Permalink to &quot;参考答案&quot;">​</a></h2><p><strong>目标</strong></p><ul><li>更快 FCP / LCP，白屏时间短，用户第一眼看到主要内容。</li><li>关键路径最短，非关键资源延后。</li></ul><p><strong>HTML</strong></p><ul><li><strong>SSR / SSG</strong>：把首屏 HTML 在服务端生成好，避开客户端渲染的等待。SSG 适合内容站，SSR 适合个性化。</li><li><strong>Streaming SSR</strong>：先把可用的部分 HTML flush 给浏览器，让浏览器边下边解析，减少 TTFB。</li><li><strong><code>103 Early Hints</code></strong>：还没生成完 HTML 时，先告诉浏览器 <code>&lt;link rel=&quot;preload&quot;&gt;</code> 关键资源。</li><li><strong>App Shell</strong>：先返回一个骨架 HTML，异步补数据。</li></ul><p><strong>CSS</strong></p><ul><li><strong>关键 CSS 内联</strong>：把首屏关键样式抽出来内联到 HTML，剩余样式异步。</li><li><strong><code>preload</code> 非关键 CSS</strong>：<code>&lt;link rel=&quot;preload&quot; href=&quot;rest.css&quot; as=&quot;style&quot; onload=&quot;this.rel=&#39;stylesheet&#39;&quot;&gt;</code>。</li><li><strong>拆分</strong>：路由 / 组件级 CSS 拆分，只加载首屏所需。</li><li><strong>避免大而全的 CSS 框架</strong>：按需引入、<code>@tailwindcss</code> 生产模式的 <code>content</code> 扫描去除未用样式。</li></ul><p><strong>JS</strong></p><ul><li><strong>代码分割</strong>：<code>import()</code> 动态加载路由 / 组件；vendors 拆分。</li><li><strong>defer / async</strong>：非关键脚本用 <code>defer</code>（不阻塞解析、按顺序执行）；独立脚本用 <code>async</code>。</li><li><strong>减小体积</strong>：Tree Shaking、Terser 压缩、去除 sourcemap（生产可外部）。</li><li><strong>Polyfill 按需</strong>：<code>@babel/preset-env</code> + <code>browserslist</code> 精准 polyfill；差异化打包（<code>nomodule</code>）。</li><li><strong>移除运行时膨胀</strong>：用 <code>esbuild</code> / <code>swc</code> 加速构建，用轻量替代（如 <code>preact</code> / <code>dayjs</code>）。</li><li><strong>首屏免 JS</strong>：能不写 JS 就不写；用原生 HTML / CSS 完成布局。</li></ul><p><strong>图片 / 字体 / 视频</strong></p><ul><li><strong>格式</strong>：AVIF &gt; WebP &gt; JPEG/PNG；小 icon 用 SVG。</li><li><strong>响应式</strong>：<code>srcset</code> + <code>sizes</code> 给不同 DPR / 视口不同资源。</li><li><strong>懒加载</strong>：<code>loading=&quot;lazy&quot;</code>（浏览器原生）或 <code>IntersectionObserver</code>。</li><li><strong>首屏图片高优先级</strong>：<code>fetchpriority=&quot;high&quot;</code> + <code>preload</code>，避免懒加载首屏。</li><li><strong>占位</strong>：低分辨率预览（LQIP）/ 骨架 / 主色块 / blurhash 缓解白屏。</li><li><strong>字体</strong>：<code>font-display: swap</code>；子集化只保留用到的字符；关键字体 <code>preload</code>。</li><li><strong>视频</strong>：<code>poster</code> 图先出、<code>preload=&quot;none&quot;</code> 节流。</li></ul><p><strong>数据 / API</strong></p><ul><li><strong>Data preloading</strong>：SSR 时把首屏数据一起塞进 HTML（如 Next <code>getServerSideProps</code>、Nuxt <code>useAsyncData</code>）。</li><li><strong>并行发起</strong>：能并发的接口别串行；用 GraphQL 聚合。</li><li><strong>Stream</strong>：接口支持 <code>text/event-stream</code> 或分段 JSON，边下边渲染。</li><li><strong>本地缓存</strong>：把上一次数据放 IndexedDB / Cache Storage，首次可即时渲染再补更新（stale-while-revalidate）。</li></ul><p><strong>Resource Hints</strong></p><ul><li><code>dns-prefetch</code>：只做 DNS 解析，几乎无成本。</li><li><code>preconnect</code>：DNS + TCP + TLS 提前建连，节省 100-300ms。</li><li><code>preload</code>：明确告诉浏览器现在就下载某个资源。</li><li><code>prefetch</code>：低优先级预取「下一页」可能用到的资源。</li><li><code>modulepreload</code>：给 ESM 模块用。</li></ul><p><strong>渲染架构演进</strong></p><ul><li>CSR（客户端渲染）→ SSR → SSG → ISR（增量静态再生成）→ Islands（局部水合）→ Server Components / Streaming。</li><li>现代框架（Next.js / Remix / Nuxt / SvelteKit / SolidStart）都在做首屏 Streaming + 局部水合。</li></ul><h2 id="追问-1-ssr-一定比-csr-首屏快吗-有哪些代价" tabindex="-1">追问 1：SSR 一定比 CSR 首屏快吗？有哪些代价？ <a class="header-anchor" href="#追问-1-ssr-一定比-csr-首屏快吗-有哪些代价" aria-label="Permalink to &quot;追问 1：SSR 一定比 CSR 首屏快吗？有哪些代价？&quot;">​</a></h2><p><strong>答</strong>：</p><ul><li><strong>不一定</strong>。SSR 的 TTFB 通常比 CSR 静态 HTML 高（要跑服务端渲染 + 拿数据），但因为 HTML 内容更完整，<strong>FCP / LCP 通常更快</strong>。</li><li>SSR 的代价： <ul><li><strong>服务端成本</strong>：每次请求都要 CPU、内存跑渲染，扩容成本高。可用缓存 / 边缘缓存缓解。</li><li><strong>首屏可交互延迟（TTI）</strong>：SSR 完 HTML 后仍要下载 JS 并「水合（hydration）」，此时页面能看不能点。可用 Streaming + Selective Hydration / Islands 缓解。</li><li><strong>实现复杂</strong>：同构代码、SSR 特有 bug（引用 window/document 会崩），数据流管理麻烦。</li><li><strong>不适合极度个性化</strong>：难缓存。</li></ul></li><li>折中：静态部分 SSG（构建时生成），动态数据客户端拉；或用 ISR（部分页面按需静态化）。</li></ul><h2 id="追问-2-preload、prefetch、preconnect、dns-prefetch-用错会有什么后果" tabindex="-1">追问 2：<code>preload</code>、<code>prefetch</code>、<code>preconnect</code>、<code>dns-prefetch</code> 用错会有什么后果？ <a class="header-anchor" href="#追问-2-preload、prefetch、preconnect、dns-prefetch-用错会有什么后果" aria-label="Permalink to &quot;追问 2：`preload`、`prefetch`、`preconnect`、`dns-prefetch` 用错会有什么后果？&quot;">​</a></h2><p><strong>答</strong>：</p><ul><li><strong>preload 用错</strong>： <ul><li>预加载了首屏不用的资源，浪费带宽、抢占关键资源的下载。</li><li>忘了 <code>as</code> 属性，浏览器不知道优先级和类型，可能忽略。</li><li>预加载后如果没被使用，控制台会告警 (「preloaded resource is not used within a few seconds」)。</li></ul></li><li><strong>prefetch 用错</strong>：预取太多，弱网用户流量白流；预取的资源缓存 key 与实际请求不同（如 CORS 属性不一致）会重复下载。</li><li><strong>preconnect 用错</strong>：给太多域名 preconnect 会消耗大量并行 TCP 连接（每个都要 DNS + TCP + TLS），移动端拖慢。一般只对 2-3 个关键第三方域名做。</li><li><strong>dns-prefetch 用错</strong>：极少见问题，成本最低；但也没必要滥用。</li><li>通用原则：只对<strong>确定首屏路径上会用到</strong>的资源做 preload / preconnect；确定「用户很可能翻到下一页」时做 prefetch；其它用 dns-prefetch 兜底。</li></ul><h2 id="追问-3-如何优化「js-太大导致-tbt-高」这类问题" tabindex="-1">追问 3：如何优化「JS 太大导致 TBT 高」这类问题？ <a class="header-anchor" href="#追问-3-如何优化「js-太大导致-tbt-高」这类问题" aria-label="Permalink to &quot;追问 3：如何优化「JS 太大导致 TBT 高」这类问题？&quot;">​</a></h2><p><strong>答</strong>：</p><ul><li><strong>拆包</strong>：路由级 <code>import()</code>，业务代码 / 第三方 vendors 分开；重的图表 / 编辑器组件懒加载。</li><li><strong>减少体积</strong>： <ul><li>分析：<code>webpack-bundle-analyzer</code>、<code>source-map-explorer</code> 看谁大。</li><li>替换重库：<code>moment</code> → <code>dayjs</code>；<code>lodash</code> → <code>lodash-es</code> 按需；<code>echarts</code> 按需引入 chart 类型。</li><li>Tree shake：<code>sideEffects: false</code>，避免副作用；避免用 <code>require</code> 破坏 tree shake。</li></ul></li><li><strong>执行时机</strong>： <ul><li><code>defer</code> / 动态 <code>import()</code> 首屏后再加载。</li><li>用 <code>requestIdleCallback</code> 在空闲时初始化非关键模块。</li></ul></li><li><strong>主线程调度</strong>： <ul><li>用 <code>scheduler.postTask</code> 分片；React 18 <code>startTransition</code> 把大更新降优先级。</li><li>复杂计算放 Web Worker。</li></ul></li><li><strong>架构</strong>： <ul><li>Islands / RSC：只把交互组件下发 JS，剩下的静态 HTML。</li><li>微前端时保证子应用独立打包 + 懒加载。</li></ul></li></ul><h2 id="参考资料" tabindex="-1">参考资料 <a class="header-anchor" href="#参考资料" aria-label="Permalink to &quot;参考资料&quot;">​</a></h2><blockquote><p>深入阅读请从标注 <strong>首选</strong> 的来源开始；本领域完整索引见 <a href="/domains/browser/RESOURCES">浏览器 &amp; 网络 参考资料</a>。</p></blockquote><ul><li><strong>首选</strong> — <a href="https://web.dev/articles/optimize-lcp" target="_blank" rel="noreferrer">web.dev: Optimize LCP</a>：首屏 LCP 优化策略</li><li><a href="https://www.w3.org/TR/resource-hints/" target="_blank" rel="noreferrer">W3C: Resource Hints</a>：preload、preconnect、dns-prefetch</li><li><a href="https://web.dev/articles/reduce-javascript-payloads-with-code-splitting" target="_blank" rel="noreferrer">web.dev: Code splitting</a>：代码分割与按需加载</li></ul>',32)])])}const S=o(s,[["render",i]]);export{u as __pageData,S as default};
